const channelData = $input.first().json;
const items = channelData.items ?? [];
const channelTags = $('Fetch curated YouTube channels').item.json.tags ?? [];

return items.map(item => ({
  json: {
    platform: 'youtube',
    external_id: item.id?.videoId ?? '',
    title: item.snippet?.title ?? null,
    description: item.snippet?.description?.slice(0, 500) ?? null,
    thumbnail_url: item.snippet?.thumbnails?.high?.url ?? item.snippet?.thumbnails?.medium?.url ?? item.snippet?.thumbnails?.default?.url ?? null,
    embed_url: `https://www.youtube.com/watch?v=${item.id?.videoId}`,
    author_name: item.snippet?.channelTitle ?? null,
    author_avatar_url: null,
    view_count: 0,
    like_count: 0,
    tags: channelTags,
    duration_seconds: null,
    published_at: item.snippet?.publishedAt ?? null,
  }
})).filter(r => r.json.external_id);

